import React, { useState } from "react";
import { Container, Button, Form, Card } from "react-bootstrap";
import "bootstrap/dist/css/bootstrap.min.css";

function SpellingGame() {
  const [wordsIKindaKnow, setWordsIKindaKnow] = useState(["apple", "banana", "cat", "dog"]);
  const [wordsIDontKnow, setWordsIDontKnow] = useState(["caset", "vreemon", "cremora"]);
  const [wordsIKnow, setWordsIKnow] = useState([]);
  const [currentWord, setCurrentWord] = useState("");
  const [userInput, setUserInput] = useState("");
  const [message, setMessage] = useState("");
  const [incorrectAttempts, setIncorrectAttempts] = useState(0);
  const [gameOver, setGameOver] = useState(false);
  const [gameWon, setGameWon] = useState(false);

  // Function to start the game
  const startGame = () => {
    setWordsIKnow([]);
    setIncorrectAttempts(0);
    setGameOver(false);
    setGameWon(false);

    if (wordsIDontKnow.length > 0) {
      setCurrentWord(wordsIDontKnow[0]);
    } else if (wordsIKindaKnow.length > 0) {
      setCurrentWord(wordsIKindaKnow[0]);
    } else {
      setGameWon(true);
    }
  };

  // Move to the next word
  const moveToNextWord = () => {
    let newWordsIDontKnow = wordsIDontKnow.filter((word) => word !== currentWord);
    let newWordsIKindaKnow = wordsIKindaKnow.filter((word) => word !== currentWord);

    setWordsIDontKnow(newWordsIDontKnow);
    setWordsIKindaKnow(newWordsIKindaKnow);

    if (newWordsIDontKnow.length > 0) {
      setCurrentWord(newWordsIDontKnow[0]);
    } else if (newWordsIKindaKnow.length > 0) {
      setCurrentWord(newWordsIKindaKnow[0]);
    } else {
      setCurrentWord("");
      setGameOver(newWordsIDontKnow.length > 0 || newWordsIKindaKnow.length > 0);
      setGameWon(newWordsIDontKnow.length === 0 && newWordsIKindaKnow.length === 0);
    }

    setIncorrectAttempts(0);
    setUserInput("");
  };

  // Function to check the spelling
  const checkSpelling = () => {
    if (userInput.toLowerCase() === currentWord.toLowerCase()) {
      setMessage("Correct!");
      setWordsIKnow((prev) => [...prev, currentWord]);

      setTimeout(() => {
        moveToNextWord();
        setMessage("");
      }, 1000);
    } else {
      setIncorrectAttempts((prev) => prev + 1);

      if (incorrectAttempts + 1 >= 6) {
        setMessage(`Incorrect! Moving to next word.`);
        setTimeout(() => {
          moveToNextWord();
          setMessage("");
        }, 1000);
      } else {
        setMessage(`Incorrect! Attempts left: ${6 - (incorrectAttempts + 1)}`);
      }
    }
  };

  return (
    <Container className="text-center mt-5">
      <Card className="p-4">
        <h1>Spelling Game</h1>
        {gameWon ? (
          <h2>Congratulations! You've won the game! 🎉</h2>
        ) : gameOver ? (
          <>
            <h2>You've Lost 😔</h2>
            <Button onClick={startGame} variant="primary">Restart Game</Button>
          </>
        ) : currentWord === "" ? (
          <Button onClick={startGame} variant="primary">Start Game</Button>
        ) : (
          <>
            <h2>Spell this word:</h2>
            <h3 className="text-danger">{currentWord}</h3>
            <Form.Control
              type="text"
              value={userInput}
              onChange={(e) => setUserInput(e.target.value)}
              className="mb-3"
            />
            <Button onClick={checkSpelling} variant="success">Submit</Button>
            <p className="mt-3">{message}</p>
            <p>Incorrect Attempts: {incorrectAttempts} / 6</p>
            <p>Words I Don't Know: <strong>{wordsIDontKnow.length}</strong></p>
            <p>Words I Kinda Know: <strong>{wordsIKindaKnow.length}</strong></p>
          </>
        )}
      </Card>
    </Container>
  );
}

export default SpellingGame;
